def sum_of_modes(nums):
    if not nums:
        return 0

    frequency = {}
    for num in nums:
        if num in frequency:
            frequency[num] += 1
        else:
            frequency[num] = 1

    max_freq = max(frequency.values())
    modes = [num for num, freq in frequency.items() if freq == max_freq]

    return sum(set(modes))

# Edge case: If all numbers appear the same number of times, they are all considered modes.
# For example, sum_of_modes([1, 2, 3, 4]) should return 0 because there is no single most frequent value.
